package com.themuffinman.app.vision.service;
import com.themuffinman.app.vision.model.VisionConversation; import org.springframework.stereotype.Service;
@Service public class VisionUpdateAvailabilityExceptionExecutionAdapter implements VisionCapabilityExecutionAdapter { private final VisionBusinessAvailabilityMutationService service; public VisionUpdateAvailabilityExceptionExecutionAdapter(VisionBusinessAvailabilityMutationService s){service=s;} public String capabilityId(){return "update_availability_exception";} public VisionExecutionResult execute(VisionConversation c){try{service.updateException(c.getSlotData(),c.getOwner());return VisionExecutionResult.executedAction(capabilityId());}catch(RuntimeException e){return VisionExecutionResult.blocked("The availability exception could not be updated.");}} }
